import time
import random

# Simulating MQTT Broker
class MockMQTTBroker:
    def __init__(self):
        self.topics = {}
        self.subscribers = {}

    def publish(self, topic, message):
        """Publisher sends message to topic"""
        if topic not in self.topics:
            self.topics[topic] = []
        self.topics[topic].append(message)
        print(f"[PUBLISHER] Sent to '{topic}': {message}")
        # Notify subscribers
        if topic in self.subscribers:
            for callback in self.subscribers[topic]:
                callback(topic, message)

    def subscribe(self, topic, callback):
        """Subscriber registers interest in a topic"""
        if topic not in self.subscribers:
            self.subscribers[topic] = []
        self.subscribers[topic].append(callback)
        print(f"[SUBSCRIBER] Subscribed to '{topic}'")

# IoT Device (Publisher) - Temperature Sensor
class TemperatureSensor:
    def __init__(self, device_id, broker):
        self.device_id = device_id
        self.broker = broker

    def read_and_publish(self):
        """Simulate reading temperature and publishing"""
        temperature = random.uniform(20, 40)  # Simulated sensor reading
        payload = f"{{\"device_id\": \"{self.device_id}\", \"temperature\": {temperature:.2f}}}"
        self.broker.publish("home/sensors/temperature", payload)

# IoT Application (Subscriber) - Smart Thermostat
class SmartThermostat:
    def __init__(self, broker):
        self.broker = broker
        self.threshold = 30.0

    def on_message_received(self, topic, message):
        """Callback when message received"""
        print(f"[THERMOSTAT] Received: {message}")
        # Parse and check threshold
        import json
        data = json.loads(message)
        if data['temperature'] > self.threshold:
            print(f"[THERMOSTAT] Temperature {data['temperature']:.2f} > {self.threshold} - Turning ON AC")
        else:
            print(f"[THERMOSTAT] Temperature {data['temperature']:.2f} <= {self.threshold} - Turning OFF AC")

# Main execution
if __name__ == "__main__":
    broker = MockMQTTBroker()

    # Create publisher (Temperature Sensor)
    sensor = TemperatureSensor("SENSOR_001", broker)

    # Create subscriber (Smart Thermostat App)
    thermostat = SmartThermostat(broker)
    broker.subscribe("home/sensors/temperature", thermostat.on_message_received)

    # Simulate IoT data flow
    print("\n--- Simulating IoT Publish-Subscribe ---\n")
    for i in range(3):
        sensor.read_and_publish()
        time.sleep(1)

