// Simulated Hardware Registers
#define SENSOR_PIN_A0  0
#define ACTUATOR_PIN_2 2
#define ACTUATOR_PIN_3 3

// Simulated register addresses
volatile int analogRegisters[6] = {0};
bool digitalPins[14] = {false};

// Mock function to simulate reading analog sensor (LM35 Temperature)
int readSensor(int pin) {
    // Simulate temperature reading between 20-35°C
    // In real hardware, this reads from ADC register
    static int mockTemp = 250;  // 25.0°C in raw ADC (x10)
    mockTemp += (rand() % 10) - 5;  // Random fluctuation
    return mockTemp;
}

// Mock function to control digital actuator (LED/Relay)
void digitalWrite(int pin, bool state) {
    digitalPins[pin] = state;
    printf("Actuator on pin %d: %s\n", pin, state ? "ON" : "OFF");
}

// Convert ADC reading to temperature in Celsius
float convertToCelsius(int rawValue) {
    // LM35: 10mV per degree, ADC: 5V/1023 = 4.89mV per unit
    // Temperature = (raw * 4.89) / 10
    return (rawValue * 489.0) / 1023.0;
}

// Main IoT Device Logic
int main() {
    printf("=== IoT Device: Temperature Monitor System ===\n\n");

    // IoT System Configuration
    const float TEMP_THRESHOLD = 30.0;  // Threshold for cooling
    const int DEVICE_ID = 1;

    // Physical Components:
    // - Sensor: LM35 Temperature Sensor (analog pin A0)
    // - Actuator: Fan (digital pin 2), LED indicator (digital pin 3)

    printf("Device ID: %d\n", DEVICE_ID);
    printf("Temperature Threshold: %.1f°C\n\n", TEMP_THRESHOLD);

    // Continuous IoT monitoring loop
    for (int iteration = 1; iteration <= 5; iteration++) {
        printf("--- Reading %d ---\n", iteration);

        // Step 1: Sensor reads physical environment
        int sensorRaw = readSensor(SENSOR_PIN_A0);
        float temperature = convertToCelsius(sensorRaw);

        printf("Raw Sensor Value: %d\n", sensorRaw);
        printf("Temperature: %.1f°C\n", temperature);

        // Step 2: Microcontroller processes data (Decision Logic)
        if (temperature > TEMP_THRESHOLD) {
            printf("Status: High temperature detected!\n");

            // Step 3: Control Actuators
            digitalWrite(ACTUATOR_PIN_2, true);   // Turn ON Fan
            digitalWrite(ACTUATOR_PIN_3, true);   // Turn ON LED warning
        } else {
            printf("Status: Temperature normal\n");

            // Turn OFF actuators
            digitalWrite(ACTUATOR_PIN_2, false);  // Turn OFF Fan
            digitalWrite(ACTUATOR_PIN_3, false);  // Turn OFF LED
        }

        // Step 4: In real IoT, data would be sent to cloud here
        printf("[Cloud] Would send: {device:%d, temp:%.1f, status:%s}\n",
               DEVICE_ID, temperature,
               temperature > TEMP_THRESHOLD ? "ALERT" : "NORMAL");

        printf("\n");
    }

    return 0;
}
